export default StaffView;

import React, { useState, useMemo, useEffect } from 'react';
import { Ticket, Station, Service, TicketStatus, UserRole } from '../types';

interface StaffViewProps {
  station: Station;
  allStations?: Station[];
  tickets: Ticket[];
  services: Service[];
  userRole?: UserRole;
  onStatusUpdate: (ticketId: string, status: TicketStatus, stationId: string) => void;
  onSelectStation?: (stationId: string) => void;
}

const StaffView: React.FC<StaffViewProps> = ({ 
  station, 
  allStations = [], 
  tickets, 
  services, 
  userRole,
  onStatusUpdate,
  onSelectStation 
}) => {
  const [elapsedTime, setElapsedTime] = useState(0);
  const isAdmin = userRole === UserRole.ADMIN || userRole === UserRole.SUPERADMIN;

  const relevantTickets = useMemo(() => 
    tickets.filter(t => 
      station.serviceIds.includes(t.serviceId) && 
      services.some(s => s.id === t.serviceId)
    ),
  [tickets, station.serviceIds, services]);

  const waitingTickets = relevantTickets.filter(t => t.status === TicketStatus.WAITING);

  const activeTicket = tickets.find(t => t.stationId === station.id && 
    (t.status === TicketStatus.CALLING || t.status === TicketStatus.ATTENDING));

  useEffect(() => {
    let interval: any;
    if (activeTicket?.status === TicketStatus.ATTENDING) {
      interval = setInterval(() => {
        setElapsedTime(Math.floor((Date.now() - (activeTicket.startedAt || Date.now())) / 1000));
      }, 1000);
    } else {
      setElapsedTime(0);
    }
    return () => clearInterval(interval);
  }, [activeTicket]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const getWaitTime = (createdAt: number) => {
    const diff = Math.floor((Date.now() - createdAt) / 60000);
    return diff > 0 ? `${diff}m` : 'Reciente';
  };

  const currentService = activeTicket ? services.find(s => s.id === activeTicket.serviceId) : null;

  return (
    <div className="flex min-h-[calc(100vh-180px)] w-full max-w-[1400px] mx-auto gap-8 p-2 animate-fade-in">
      {/* Sidebar - Enhanced Admin Control */}
      {isAdmin && allStations.length > 0 && (
        <aside className="w-80 flex-shrink-0 hidden lg:flex flex-col gap-4">
          <div className="bg-white/80 backdrop-blur-2xl border border-slate-200/50 rounded-[2.5rem] p-8 shadow-xl shadow-slate-200/40 flex flex-col h-full">
            <div className="mb-8">
              <span className="text-[10px] font-black text-indigo-500 uppercase tracking-[0.4em] block mb-1">Network Control</span>
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Módulos Activos</h3>
            </div>

            <div className="space-y-3 overflow-y-auto pr-3 custom-scrollbar flex-grow -mr-2">
              {allStations.map(s => {
                const isActive = s.id === station.id;
                const stationWaitingCount = tickets.filter(t => 
                  t.status === TicketStatus.WAITING && s.serviceIds.includes(t.serviceId)
                ).length;
                const activeOnStation = tickets.find(t => 
                  t.stationId === s.id && (t.status === TicketStatus.CALLING || t.status === TicketStatus.ATTENDING)
                );

                return (
                  <button
                    key={s.id}
                    onClick={() => onSelectStation?.(s.id)}
                    className={`w-full text-left p-5 rounded-3xl transition-all border group relative overflow-hidden ${
                      isActive 
                        ? "bg-slate-900 border-slate-900 text-white shadow-2xl shadow-slate-400" 
                        : "bg-slate-50 border-slate-100 text-slate-600 hover:border-indigo-200 hover:bg-white hover:shadow-lg"
                    }`}
                  >
                    <div className="relative z-10 flex justify-between items-center">
                      <div className="space-y-1">
                        <div className="flex items-center gap-2">
                           <div className={`w-1.5 h-1.5 rounded-full ${activeOnStation ? 'bg-emerald-500 animate-pulse' : 'bg-slate-300'}`}></div>
                           <p className={`text-[10px] font-black uppercase tracking-widest ${isActive ? 'text-indigo-400' : 'text-slate-400'}`}>
                             {s.name}
                           </p>
                        </div>
                        <p className="text-sm font-black tracking-tight truncate max-w-[150px]">{s.operatorName}</p>
                        {activeOnStation && (
                          <span className={`text-[10px] font-bold ${isActive ? 'text-slate-400' : 'text-indigo-500'}`}>
                            Atendiendo: {activeOnStation.code}
                          </span>
                        )}
                      </div>
                      <div className="flex flex-col items-end gap-2">
                        {stationWaitingCount > 0 && (
                          <span className={`text-[10px] font-black px-2 py-1 rounded-xl shadow-sm ${isActive ? 'bg-indigo-600 text-white' : 'bg-white text-slate-900 border border-slate-200'}`}>
                            {stationWaitingCount}
                          </span>
                        )}
                      </div>
                    </div>
                  </button>
                );
              })}
            </div>

